#!/usr/bin/perl

use strict;
use warnings;
use CGI qw(:standard);
use URI::Escape;

my $cgi = new CGI;
my $redirect_url = $cgi->param('next');

# Validate redirect URL
if ($redirect_url && $redirect_url =~ /^https?:\/\//) {
    # Ensure the redirect is to a valid domain (optional security check)
    # You can customize this based on your requirements
    print "Location: " . uri_unescape($redirect_url) . "\n\n";
} else {
    # Default redirect if no valid next parameter
    print "Location: /dashboard\n\n";
}